rss.channel:
{{ channel.title | e }}
{{ channel.link | e }}
{{ channel.description | e }}
{{ channel.language | e }}
{{ channel.last_build_date.strftime('%a, %d %b %Y %H:%M:%S +0000') }}

{% for item in items %}


  {{ item.title | e }}
  {{ item.link | e }}
  {{ item.guid | e }}
  {{ item.description | e }}
  {% if item.published_at %}
  {{ item.published_at.strftime('%a, %d %b %Y %H:%M:%S +0000') }}
  {% endif %}
  {{ item.author_name | e }}
  {% for tag in item.tags %}
  {{ tag | e }}
  {% endfor %}

{% endfor %}
